<?php
namespace App\Http\Requests;
use Illuminate\Foundation\Http\FormRequest; use Illuminate\Support\Str;
class StoreCampaignRequest extends FormRequest { public function authorize(): bool { return $this->user()?->isRole('admin') || $this->user()?->isRole('fundraiser'); } public function rules(): array { return ['category_id'=>['required','exists:campaign_categories,id'],'title'=>['required','string','max:180'],'short_description'=>['required','string','max:300'],'story'=>['required','string','max:10000'],'target_amount'=>['required','numeric','min:10000','max:1000000000'],'thumbnail'=>['nullable','image','mimes:jpg,jpeg,png,webp','max:2048'],'supporting_document'=>['nullable','file','mimes:pdf,jpg,jpeg,png','max:4096'],'starts_at'=>['nullable','date'],'ends_at'=>['nullable','date','after_or_equal:starts_at'],'location'=>['required','string','max:120']]; } protected function prepareForValidation(): void { $this->merge(['title'=>strip_tags((string)$this->title),'location'=>Str::of((string)$this->location)->stripTags()->trim()->value() ?: 'Sumatera Selatan']); } }
